import sys, json, base64, ast
sys.path.insert(0, ".")

# 1. Install updated calendar.py
open("pacing/calendar.py", "wb").write(base64.b64decode(""))
ast.parse(open("pacing/calendar.py").read())
print("1. calendar.py updated (revenue boxes + content rules + DB retry)")

# 2. Fix db/__init__.py
init = open("db/__init__.py").read()
init = init.replace("from .connection import get_conn, get_pool", "from .connection import get_conn")
open("db/__init__.py", "w").write(init)
print("2. db/__init__.py fixed")

# 3. Load calendar and republish with new HTML
calendar = json.loads(base64.b64decode("").decode())

from db.connection import get_conn
with get_conn() as conn:
    with conn.cursor() as cur:
        cur.execute(
            "INSERT INTO decisions (decided_by, decision_type, input_context, reasoning, output) "
            "VALUES (%s, %s, %s::jsonb, %s, %s::jsonb)",
            ("claude_direct", "calendar_plan",
             json.dumps({"source": "manual_complete_v2", "month": "2026-05"}),
             "Complete May 14-31 with revenue summaries. Hive Mind every 3d, sleep audio every 3d, pre-paid/membership, Memorial Day, weekends.",
             json.dumps(calendar)))
    conn.commit()
    print("3. Calendar inserted into DB")

from pacing.calendar import _generate_html_report, _publish_calendar_page
from datetime import date
html = _generate_html_report(date(2026, 5, 1), calendar)
url = _publish_calendar_page(date(2026, 5, 1), html)
print("4. Published:", url)
print()
print("Done. Revenue summaries now show on the calendar page.")
print("Test from Slack: type 'generate calendar' to regenerate fresh.")
